@charset "UTF-8";
#map-container {
  width: 100%;
  height: 100%;
  position: relative;
}

#map {
  width: 100%;
  height: 400px; /* Ajusta según el tamaño de tu widget */
  background: #f8f9fa;
  border-radius: 8px;
}

.info {
  padding: 10px;
  font-family: Arial, sans-serif;
  background: white;
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 0 15px rgba(0, 0, 0, 0.2);
  border-radius: 5px;
  position: absolute;
  top: 10px;
  right: 10px;
  z-index: 1000;
  min-width: 150px;
}

.info h4 {
  margin: 0 0 5px;
  color: #777;
}

