function renderGeoJSON() {
  const geojson = appsmith.model.mapaData;
  if (!geojson || !map) return;
  if (geojsonLayer) map.removeLayer(geojsonLayer);
  geojsonLayer = L.geoJson(geojson, {
    style: feature => {
      // Resaltado: Si tiene registros, pintamos de un color más fuerte
      const tieneData = feature.properties.total > 0;
      return {
        fillColor: tieneData ? '#2ecc71' : '#bdc3c7',
        // Verde si hay, Gris si no
        weight: 2,
        opacity: 1,
        color: 'white',
        fillOpacity: tieneData ? 0.7 : 0.3
      };
    },
    onEachFeature: (feature, layer) => {
      layer.on({
        mouseover: e => {
          const p = feature.properties;
          const content = `<b>${p.NOMBRE}</b><br>Total: ${p.total}<br><small>${p.info}</small>`;
          document.getElementById('info-content').innerHTML = content;
          e.target.setStyle({
            weight: 4,
            color: '#333',
            fillOpacity: 0.9
          });
        },
        mouseout: e => {
          geojsonLayer.resetStyle(e.target);
          document.getElementById('info-content').innerHTML = 'Pasa el ratón sobre un municipio';
        }
      });
    }
  }).addTo(map);
}

